#include<bits/stdc++.h>
using namespace std;
int cnt[50010],c[50010];
int blksiz;
struct node
{
	int l,r,id;
	bool operator<(const node&b)const
	{
		if(l/blksiz!=b.l/blksiz)
		{
			return l<b.l;
		}
		if((l/blksiz)%2==1)
		{
			return r<b.r;
		}
		return r>b.r;
	}
}q[50010];
long long res,ans[50010];
void add(int x)
{
	res-=1ll*cnt[c[x]]*cnt[c[x]];
	cnt[c[x]]++;
	res+=1ll*cnt[c[x]]*cnt[c[x]];
}
void del(int x)
{
	res-=1ll*cnt[c[x]]*cnt[c[x]];
	cnt[c[x]]--;
	res+=1ll*cnt[c[x]]*cnt[c[x]];
}
int main()
{
	int n,m,k;
	scanf("%d%d%d",&n,&m,&k);
	blksiz=sqrt(n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&c[i]);
	}
	for(int i=1;i<=m;i++)
	{
		scanf("%d%d",&q[i].l,&q[i].r);
		q[i].id=i;
	}
	sort(q+1,q+1+m);
	int l=1,r=0;
	for(int i=1;i<=m;i++)
	{
		while(l>q[i].l)
		{
			add(--l);
		}
		while(r<q[i].r)
		{
			add(++r);
		}
		while(l<q[i].l)
		{
			del(l++);
		}
		while(r>q[i].r)
		{
			del(r--);
		}
		ans[q[i].id]=res;
	}
	for(int i=1;i<=m;i++)
	{
		printf("%lld\n",ans[i]);
	}
	return 0;
}
